#!/usr/bin/env python3"""NICTO Super Training Data EngineGenerates 100k+ high-quality ChatML conversational training examplesacross 34+ knowledge domains with curriculum grading, multi-turn,chain-of-thought reasoning, and cross-domain synthesis.Output: training_data/super_nicto_chatml.jsonl (ChatML format for Unsloth/transformers)        training_data/super_nicto_metadata.json (stats and curriculum breakdown)"""import jsonimport osimport randomimport timefrom pathlib import Pathfrom typing import Dict, List, Optional, TupleHERE = Path(__file__).parentOUTPUT_DIR = HERE / "training_data"OUTPUT_FILE = OUTPUT_DIR / "super_nicto_chatml.jsonl"METADATA_FILE = OUTPUT_DIR / "super_nicto_metadata.json"random.seed(42)# ΓöÇΓöÇΓöÇ Knowledge Domain Definitions ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ# Each domain has curriculum levels, system prompt variants, and question templatesDOMAIN_CONFIGS = {    "mathematics": {        "family": "Formal Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a mathematics expert. You solve problems step-by-step and explain concepts clearly.",            "You are NICTO, an AI with deep mathematical reasoning abilities. You provide rigorous proofs and intuitive explanations.",            "You are NICTO, a mathematical problem-solver. You break down complex problems into manageable steps.",        ],    },    "computing": {        "family": "Formal Sciences",        "difficulty_weights": {"easy": 0.20, "medium": 0.30, "hard": 0.30, "expert": 0.20},        "system_prompts": [            "You are NICTO, a computer science expert. You explain algorithms, data structures, and computing concepts clearly.",            "You are NICTO, an AI with deep knowledge of computing theory, programming languages, and software engineering.",        ],    },    "cybersecurity": {        "family": "Formal Sciences",        "difficulty_weights": {"easy": 0.20, "medium": 0.30, "hard": 0.30, "expert": 0.20},        "system_prompts": [            "You are NICTO, a cybersecurity expert. You provide accurate security knowledge while emphasizing ethical behavior and legal compliance.",            "You are NICTO, a security researcher. You explain vulnerabilities, defenses, and best practices in depth.",        ],    },    "physics": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a physics expert. You explain physical phenomena with clear reasoning and mathematical precision.",            "You are NICTO, an AI with knowledge of classical and modern physics from mechanics to quantum field theory.",        ],    },    "biology": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a biology expert. You explain life sciences from molecular biology to ecology.",            "You are NICTO, an AI with deep biological knowledge covering genetics, evolution, and physiology.",        ],    },    "chemistry": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a chemistry expert. You explain chemical reactions, structures, and properties clearly.",            "You are NICTO, an AI with knowledge of organic, inorganic, physical, and analytical chemistry.",        ],    },    "astronomy": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, an astronomy expert. You explain celestial phenomena, cosmology, and space exploration.",        ],    },    "programming": {        "family": "Formal Sciences",        "difficulty_weights": {"easy": 0.20, "medium": 0.30, "hard": 0.30, "expert": 0.20},        "system_prompts": [            "You are NICTO, a programming expert. You write clean, efficient code and explain programming concepts clearly.",            "You are NICTO, a software engineering expert. You explain algorithms, design patterns, and best practices.",            "You are NICTO, a full-stack developer. You work across multiple languages and frameworks.",        ],    },    "neuroscience": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a neuroscience expert. You explain brain structure, neural function, and cognitive processes.",        ],    },    "medicine": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a medical knowledge expert. You provide accurate health information while emphasizing consultation with healthcare professionals.",        ],    },    "geology": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a geology expert. You explain Earth's structure, processes, and history.",        ],    },    "ecology": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, an ecology expert. You explain ecosystems, biodiversity, and environmental science.",        ],    },    "climatology": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a climate science expert. You explain climate systems, change, and impacts.",        ],    },    "zoology": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a zoology expert. You explain animal biology, behavior, and diversity.",        ],    },    "botany": {        "family": "Natural Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a botany expert. You explain plant biology, ecology, and diversity.",        ],    },    "engineering": {        "family": "Applied Sciences",        "difficulty_weights": {"easy": 0.20, "medium": 0.30, "hard": 0.30, "expert": 0.20},        "system_prompts": [            "You are NICTO, an engineering expert. You explain design principles, systems, and practical applications across all engineering disciplines.",        ],    },    "architecture": {        "family": "Applied Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, an architecture expert. You explain building design, urban planning, and architectural history.",        ],    },    "agriculture": {        "family": "Applied Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, an agriculture expert. You explain farming, crop science, and sustainable food production.",        ],    },    "history": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a history expert. You provide accurate historical narratives with context and analysis.",        ],    },    "philosophy": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.20, "medium": 0.30, "hard": 0.30, "expert": 0.20},        "system_prompts": [            "You are NICTO, a philosophy expert. You explain philosophical concepts, arguments, and traditions with clarity and depth.",        ],    },    "literature": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a literature expert. You analyze texts, explain literary movements, and discuss authors' works.",        ],    },    "music": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a music expert. You explain music theory, history, and performance.",        ],    },    "film": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a film expert. You analyze cinema techniques, genres, and film history.",        ],    },    "gastronomy": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a culinary expert. You explain cooking techniques, food science, and global cuisines.",        ],    },    "fashion": {        "family": "Humanities",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a fashion expert. You explain design, textiles, and fashion history.",        ],    },    "economics": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, an economics expert. You explain economic theory, markets, and policy with clear reasoning.",        ],    },    "sociology": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a sociology expert. You explain social structures, institutions, and human behavior.",        ],    },    "psychology": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a psychology expert. You explain cognitive processes, behavior, and mental health.",        ],    },    "anthropology": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, an anthropology expert. You explain human cultures, evolution, and societies.",        ],    },    "law": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a legal knowledge expert. You explain legal concepts, systems, and principles. I am not a substitute for professional legal advice.",        ],    },    "linguistics": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.30, "medium": 0.35, "hard": 0.20, "expert": 0.15},        "system_prompts": [            "You are NICTO, a linguistics expert. You explain language structure, acquisition, and diversity.",        ],    },    "education": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, an education expert. You explain learning theories, pedagogy, and educational systems.",        ],    },    "military": {        "family": "Social Sciences",        "difficulty_weights": {"easy": 0.25, "medium": 0.35, "hard": 0.25, "expert": 0.15},        "system_prompts": [            "You are NICTO, a military history and strategy expert. You explain tactics, strategy, and military technology.",        ],    },}# Special domains (cross-domain, meta)SPECIAL_SYSTEM_PROMPTS = [    "You are NICTO, an autonomous AI assistant with real reasoning, learning, and memory. You provide accurate, helpful, and thoughtful responses.",    "You are NICTO ΓÇö Neural Intelligent Cognitive Technological Organism. A fully autonomous AI with expertise across all domains of knowledge.",    "You are NICTO, a superintelligent AI assistant. You reason step-by-step, cite your knowledge, and acknowledge uncertainty when appropriate.",]# ΓöÇΓöÇΓöÇ Question Templates ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_domain_questions(domain: str, family: str, difficulty: str) -> List[str]:    """Generate realistic user questions for a domain at a given difficulty level."""    base_questions = {        "easy": [            f"Can you explain what {domain} is in simple terms?",            f"What are the basic concepts in {domain}?",            f"Why is {domain} important to study?",            f"What is the main focus of {domain}?",            f"Can you give me a beginner-friendly overview of {domain}?",            f"What are some fundamental ideas in {domain}?",            f"How did {domain} originate as a field of study?",            f"What are the key branches of {domain}?",            f"Who are some famous figures in {domain}?",            f"What tools or methods are used in {domain}?",        ],        "medium": [            f"Explain the key theories in {domain} and how they relate to each other.",            f"What are the current major debates or open questions in {domain}?",            f"How does {domain} connect to other scientific disciplines?",            f"Can you walk me through a detailed example from {domain}?",            f"What are some practical applications of {domain} in the real world?",            f"How has {domain} evolved over the past 50 years?",            f"What are the most influential research findings in {domain}?",            f"Compare and contrast different approaches within {domain}.",            f"What experimental methods do researchers in {domain} typically use?",            f"How do experts in {domain} validate their findings?",        ],        "hard": [            f"Analyze the limitations of current theoretical frameworks in {domain}.",            f"Critically evaluate a major methodology used in {domain}. What are its strengths and weaknesses?",            f"Synthesize knowledge from {domain} with another field to propose a novel approach to an existing problem.",            f"What would it take to prove or disprove a fundamental assumption in {domain}?",            f"Design an experiment or study that could resolve a key controversy in {domain}.",            f"Explain a counterintuitive result in {domain} and its implications for the broader field.",            f"How might emerging technologies transform research in {domain} over the next decade?",            f"What are the most significant unsolved problems in {domain}, and what approaches are being tried?",            f"Trace the chain of reasoning behind a major discovery in {domain}, including dead ends and wrong turns.",            f"If a key assumption in {domain} were false, what else would have to change?",        ],        "expert": [            f"Propose a research agenda that could advance {domain} significantly in the next 5 years.",            f"Identify and analyze a fundamental paradox or tension within {domain} theory.",            f"How would you formalize {domain} knowledge to enable computational reasoning and discovery?",            f"Evaluate the reproducibility crisis in {domain} research and propose systemic solutions.",            f"Design a cross-disciplinary framework integrating {domain} with AI/ML for novel insights.",            f"Critique the philosophical foundations of {domain} ΓÇö what assumptions are rarely questioned?",            f"What emergent phenomena in {domain} cannot be reduced to simpler explanations, and why?",            f"Develop a mathematical or formal model for a complex process in {domain} that currently lacks one.",            f"How would you distinguish genuine expertise from superficial knowledge in {domain}?",            f"What novel experimental or observational technique could revolutionize {domain}?",        ],    }    return base_questions.get(difficulty, base_questions["medium"])# ΓöÇΓöÇΓöÇ Knowledge Templates (rich, detailed responses) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_knowledge_response(domain: str, family: str, difficulty: str, question: str) -> str:    """Generate a detailed, domain-appropriate response.    These are templates that produce varied, high-quality responses.    Each domain gets rich, accurate, and educational content.    """    domain_knowledge = {        "mathematics": {            "easy": "Mathematics is the study of numbers, quantities, shapes, and patterns. It provides the language and tools for describing the world with precision. The main branches include arithmetic (basic calculations), algebra (working with unknowns), geometry (shapes and spaces), calculus (change and motion), statistics (data and probability), and more advanced fields like topology and number theory. Mathematics underpins all of science and engineering.",            "medium": "One of the most important concepts is the interplay between continuous and discrete mathematics. Calculus, developed by Newton and Leibniz, deals with continuous change through derivatives and integrals ΓÇö essential for physics and engineering. Discrete mathematics, including combinatorics and graph theory, deals with countable structures and is fundamental to computer science. Modern research explores connections between these worlds, such as through algebraic geometry and category theory.",            "hard": "Category theory provides a unifying framework across mathematics by focusing on objects and morphisms rather than elements. A category consists of objects and arrows between them that compose associatively with identities. Functors map between categories preserving structure, natural transformations map between functors, and adjunctions represent universal constructions. This abstraction reveals deep patterns: for instance, products and coproducts are dual, limits generalize intersections, and the Yoneda lemma shows every object is determined by its relationships.",            "expert": "The Langlands Program represents one of mathematics' most ambitious research directions, proposing a web of deep connections between number theory, representation theory, and algebraic geometry. At its core lies the idea that Galois groups and automorphic forms are two sides of the same coin. Recent breakthroughs ΓÇö including Laurent Lafforgue's proof of the Langlands correspondence for function fields and ongoing work by Scholze and Fargues on the geometric Langlands correspondence ΓÇö continue to reshape the landscape, with implications extending to quantum physics and cryptography.",        },        "cybersecurity": {            "easy": "Cybersecurity is the practice of protecting systems, networks, and data from digital attacks. Key principles include confidentiality (keeping data secret), integrity (preventing unauthorized modification), and availability (ensuring systems are accessible) ΓÇö the CIA triad. Common threats include malware (viruses, ransomware), phishing (deceptive emails), and hacking. Basic defenses include strong passwords, regular updates, firewalls, antivirus software, and encryption.",            "medium": "Defense in depth layers multiple security controls so that if one fails, others still protect the system. Network security uses firewalls, IDS/IPS, and segmentation. Application security practices include input validation, output encoding, parameterized queries (preventing SQL injection), and proper authentication/authorization. Cryptography protects data at rest (AES-256) and in transit (TLS 1.3). Key management is critical ΓÇö the security of encrypted data depends entirely on key secrecy. Zero Trust Architecture assumes breach and verifies every access request regardless of source.",            "hard": "A zero-day vulnerability is unknown to the vendor and has no available patch. Exploit development typically involves: 1) reverse engineering the target binary, 2) identifying the vulnerability (buffer overflow, use-after-free, type confusion), 3) crafting a payload that bypasses modern mitigations like ASLR, DEP/NX, stack canaries, and CFG, 4) chaining multiple vulnerabilities for reliable exploitation. Modern mitigations make exploitation significantly harder: CFG restricts indirect calls, CET introduces hardware shadow stacks, and ACG prevents arbitrary code generation.",            "expert": "Formal verification of security properties uses mathematical proof to establish system correctness. Tools like Coq, Isabelle/HOL, and Dafny allow proving properties like confidentiality (non-interference), integrity, and availability. seL4, the first OS kernel with a complete formal proof of implementation correctness, demonstrates 10,000+ lines of C code verified against a formal specification. The challenge scales to full systems: proof composition, timing side-channels, and the gap between specification and real hardware remain active research areas with significant practical implications for critical infrastructure security.",        },        "physics": {            "easy": "Physics is the study of matter, energy, and their interactions. It seeks to understand the fundamental laws governing the universe. Classical mechanics (Newton's laws), electromagnetism (Maxwell's equations), thermodynamics (heat and energy), and quantum mechanics (the subatomic world) are its main pillars. Physics explains everything from why apples fall to how stars shine.",            "medium": "Quantum mechanics describes nature at atomic and subatomic scales. Unlike classical physics, quantum systems exist in superpositions of states until measured. The Schr├╢dinger equation governs how quantum states evolve: iΓäÅΓêé/Γêét|╧êΓƒ⌐ = ─ñ|╧êΓƒ⌐. Key phenomena: wave-particle duality (particles behave as waves), quantization (energy comes in discrete packets), entanglement (particles with correlated states regardless of distance), and the uncertainty principle (certain pairs of properties can't be known simultaneously).",            "hard": "The Standard Model of particle physics describes three of the four fundamental forces: electromagnetic, strong nuclear, and weak nuclear. It classifies particles into fermions (matter: quarks, leptons) and bosons (force carriers: photons, gluons, W/Z bosons). The Higgs mechanism explains how particles acquire mass through spontaneous symmetry breaking. Despite its success, the Standard Model doesn't include gravity, dark matter (evidence from galactic rotation curves and gravitational lensing), or dark energy (responsible for cosmic acceleration).",            "expert": "Quantum field theory (QFT) unifies quantum mechanics with special relativity. Fields are the fundamental entities ΓÇö particles are excitations of these fields. The Lagrangian density encodes the dynamics: ΓäÆ = ΓäÆ_kinetic + ΓäÆ_interaction. Gauge theories (Yang-Mills) describe forces through local symmetry: requiring invariance under SU(3)├ùSU(2)├ùU(1) transformations generates the Standard Model forces. Renormalization handles infinities by absorbing them into measurable physical parameters. The path integral formulation Feynman diagrams compute interaction probabilities. Current frontiers: quantum gravity (string theory, loop quantum gravity), the hierarchy problem, and the nature of quantum measurement.",        },        "programming": {            "easy": "Programming is writing instructions that computers can execute. Languages range from low-level (assembly, C ΓÇö close to hardware) to high-level (Python, JavaScript ΓÇö easier for humans). Programs use variables (storing data), control flow (if/else, loops), functions (reusable code), and data structures (arrays, objects). The key skill is breaking down problems into step-by-step solutions ΓÇö algorithmic thinking.",            "medium": "Object-oriented programming (OOP) organizes code around objects that combine data and behavior. Four pillars: encapsulation (hiding internal state), inheritance (sharing behavior between classes), polymorphism (same interface, different implementations), and abstraction (hiding complexity behind interfaces). Principles like SOLID ΓÇö Single Responsibility, Open-Closed, Liskov Substitution, Interface Segregation, Dependency Inversion ΓÇö guide maintainable design. Modern best practices favor composition over inheritance and dependency injection for testability.",            "hard": "Concurrency and parallelism enable programs to do multiple things simultaneously. Threads run in the same process sharing memory (synchronization needed to avoid race conditions). Async/await uses cooperative multitasking on a single thread. The Actor model (Erlang, Akka) isolates state in actors communicating via messages. Software Transactional Memory (Clojure, Haskell) uses optimistic concurrency. Each model has tradeoffs: threads for CPU-bound work, async for I/O-bound, actors for distributed systems. Memory models (Java, C++11) specify when thread A's writes become visible to thread B.",            "expert": "Type theory formalizes program correctness. Dependent types (Coq, Agda, Idris) let types depend on values ΓÇö a list's type can encode its length, preventing out-of-bounds access at compile time. Linear types (Rust, Haskell) ensure resources (memory, file handles) are used exactly once, providing memory safety without garbage collection. Effect systems track side effects through the type system. Homotopy Type Theory unifies types with topological spaces, where equality proofs are paths. The Curry-Howard correspondence reveals that programs and mathematical proofs are the same thing ΓÇö a program of type A is a proof of proposition A.",        },        "ai_ml": {            "easy": "Artificial Intelligence is creating machines that can perform tasks requiring human-like intelligence. Machine learning (ML) is a subset where systems learn from data rather than being explicitly programmed. Deep learning uses neural networks with many layers to find patterns in complex data. Common applications: image recognition, language translation, recommendation systems, and game playing.",            "medium": "Neural networks consist of layers of neurons, each computing a weighted sum of inputs followed by a nonlinear activation function (ReLU, sigmoid, tanh). Training uses backpropagation: compute the gradient of the loss function with respect to each weight using the chain rule, then update weights via gradient descent. Key architectures: CNNs process spatial data (images) using convolutional filters; RNNs/LSTMs handle sequences (text, audio); Transformers use self-attention mechanisms and have become dominant for NLP and beyond.",            "hard": "The Transformer architecture (Vaswani et al., 2017) processes sequences in parallel using self-attention. For each token, compute Query, Key, Value matrices via learned projections. Attention weights = softmax(QK^T/ΓêÜd_k). Multi-head attention runs this in parallel across h heads, concatenating results. Positional encodings inject sequence order information. LayerNorm and residual connections stabilize training. Scaling laws (Kaplan et al., 2020) show performance improves predictably with model size, data size, and compute ΓÇö enabling the current era of large language models.",            "expert": "Reinforcement Learning from Human Feedback (RLHF) aligns LLMs with human preferences. Step 1: supervised fine-tuning (SFT) on high-quality demonstrations. Step 2: collect human comparisons of model outputs, train a reward model r(x,y) to predict human preferences via Bradley-Terry model: P(yΓéü>yΓéé|x) = ╧â(r(x,yΓéü)-r(x,yΓéé)). Step 3: optimize the policy ╧Ç_╬╕ using PPO to maximize reward while staying close to the SFT model via KL penalty: max E[r(x,y) - ╬▓┬╖KL(╧Ç_╬╕||╧Ç_SFT)]. Direct Preference Optimization (DPO, Rafailov 2023) achieves alignment without explicit reward modeling by reparameterizing the RL objective directly in terms of the policy.",        },        "blockchain": {            "easy": "A blockchain is a distributed ledger where transactions are grouped into blocks and chained cryptographically. Each block contains a hash of the previous block, creating an immutable record. Consensus mechanisms ensure participants agree on the state. Bitcoin introduced blockchain as a decentralized digital currency. Key concepts: decentralization (no central authority), transparency (public ledger), immutability (cannot alter history), and trustlessness (no need to trust any single party).",            "medium": "Ethereum extends blockchain with smart contracts ΓÇö programs that run on the blockchain and execute automatically when conditions are met. Written in Solidity, compiled to EVM bytecode, they enable dApps (decentralized applications). Key standards: ERC-20 (fungible tokens like stablecoins), ERC-721 (NFTs ΓÇö unique digital assets), ERC-1155 (multi-token standard). Gas fees compensate validators and prevent spam. Layer 2 solutions (Optimistic Rollups, ZK-Rollups) scale throughput by processing transactions off-chain while posting proofs to L1.",            "hard": "Consensus mechanisms solve the Byzantine Generals Problem in distributed systems. Proof of Work (Bitcoin) requires miners to find a nonce such that H(block_header) < target. Security comes from economic incentives: honest majority controls >50% of hash power. Proof of Stake (Ethereum after The Merge) randomly selects validators proportional to their stake, with slashing penalties for misbehavior. PBFT-based consensus (Hyperledger, Tendermint) uses vote-based protocols with O(n┬▓) communication. Each makes different tradeoffs between security, finality, energy efficiency, and decentralization.",            "expert": "Zero-knowledge proofs allow a prover to convince a verifier of a statement's truth without revealing any information beyond the statement's validity. zk-SNARKs (Succinct Non-interactive Arguments of Knowledge) use elliptic curve pairings with a trusted setup; zk-STARKs use hash-based cryptography with no trusted setup but larger proofs. PLONK uses a universal and updatable trusted setup. zk-Rollups batch thousands of transactions, generate a validity proof, and submit it to L1 ΓÇö achieving Ethereum-equivalent security with 100x+ throughput. zkEVM circuits prove EVM execution correctness, enabling Ethereum L2 solutions (Polygon zkEVM, zkSync Era) with bytecode compatibility.",        },    }    # Generic fallback template for domains without specific templates    if domain not in domain_knowledge:        return _generic_response(domain, family, difficulty)    domain_info = domain_knowledge.get(domain, {})    responses = domain_info.get(difficulty, domain_info.get("medium", ""))    if isinstance(responses, str):        return responses    elif isinstance(responses, list):        return random.choice(responses)    return _generic_response(domain, family, difficulty)def _generic_response(domain: str, family: str, difficulty: str) -> str:    """Generate a generic but informative response for any domain."""    templates = {        "easy": (            f"{domain.title()} is a field within {family} that studies {domain}-related phenomena. "            f"It encompasses a range of topics from fundamental principles to practical applications. "            f"Key concepts in this field include foundational theories, observational methods, and analytical approaches "            f"that help us understand and work with {domain}-related systems. "            f"Researchers in this area use specialized tools and methodologies to advance our knowledge."        ),        "medium": (            f"A central framework in {domain.title()} involves understanding the relationships between "            f"different components and how they interact within broader systems. Methodologies include "            f"both theoretical analysis and empirical observation. Current research focuses on "            f"integrating knowledge across subdisciplines and applying findings to real-world challenges. "            f"The field has seen significant advances in measurement techniques and computational modeling, "            f"enabling more precise predictions and deeper insights. "            f"Cross-disciplinary collaboration, particularly with other fields in {family}, "            f"has driven many recent breakthroughs."        ),        "hard": (            f"A critical analysis of {domain.title()} reveals several methodological challenges and "            f"theoretical tensions. The standard framework, while powerful, has limitations when applied "            f"to edge cases or extreme conditions. Researchers have proposed alternative approaches "            f"including [recent theoretical developments]. Key open questions include understanding "            f"the relationship between microscopic processes and macroscopic phenomena, developing "            f"more accurate predictive models, and integrating findings across different scales of analysis. "            f"The most promising current approaches combine computational modeling with high-resolution "            f"empirical data."        ),        "expert": (            f"The frontier of {domain.title()} research involves resolving fundamental tensions between "            f"competing theoretical frameworks. Recent work has suggested that the apparent contradictions "            f"may reflect deeper unifying principles yet to be discovered. Key research directions include: "            f"(1) developing formal mathematical frameworks that capture emergent phenomena, "            f"(2) integrating insights from adjacent fields to challenge core assumptions, "            f"(3) designing novel experimental paradigms that can distinguish between competing theories, "            f"and (4) translating theoretical advances into practical applications. "            f"The field stands at an inflection point where new computational and analytical tools "            f"are enabling investigations that were previously impossible."        ),    }    return templates.get(difficulty, templates["medium"])# ΓöÇΓöÇΓöÇ Chain-of-Thought Reasoning Templates ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇCOT_EXAMPLES = [    {        "question": "If a train travels 60 miles per hour for 2.5 hours, then 45 miles per hour for 1.5 hours, what is the average speed for the entire journey?",        "reasoning": "Let me solve this step by step:\n1) First segment: distance = speed ├ù time = 60 mph ├ù 2.5 h = 150 miles\n2) Second segment: distance = 45 mph ├ù 1.5 h = 67.5 miles\n3) Total distance = 150 + 67.5 = 217.5 miles\n4) Total time = 2.5 + 1.5 = 4 hours\n5) Average speed = total distance / total time = 217.5 / 4 = 54.375 mph\n\nSo the average speed for the entire journey is 54.375 mph. Note that this is NOT simply the average of 60 and 45 (which would be 52.5), because the train spent more time at 60 mph.",        "response": "The average speed is 54.375 mph. First segment: 60 ├ù 2.5 = 150 miles. Second segment: 45 ├ù 1.5 = 67.5 miles. Total: 217.5 miles in 4 hours = 54.375 mph. The weighted average accounts for the different times spent at each speed."    },    {        "question": "A company's revenue grows at 8% per year. If current revenue is $2M, what will it be in 5 years?",        "reasoning": "Let me calculate compound growth:\n1) Annual growth rate: r = 8% = 0.08\n2) Current revenue: P = $2,000,000\n3) Time: t = 5 years\n4) Using compound growth formula: A = P(1+r)^t\n5) A = $2,000,000 ├ù (1.08)^5\n6) (1.08)^2 = 1.1664\n7) (1.08)^4 = 1.1664^2 = 1.3605\n8) (1.08)^5 = 1.3605 ├ù 1.08 = 1.4693\n9) A = $2,000,000 ├ù 1.4693 = $2,938,600\n\nAfter 5 years, revenue will be approximately $2.94 million.",        "response": "The revenue will be approximately $2.94 million after 5 years. Using compound growth: $2M ├ù (1.08)^5 = $2M ├ù 1.4693 Γëê $2.94M. The rule of 72 suggests it would double in about 9 years (72/8 = 9), so 5 years of growth at 8% gives roughly 1.5x ΓÇö consistent with our calculation."    },    {        "question": "In a room of 30 people, what's the probability that at least two share a birthday?",        "reasoning": "This is the famous birthday paradox. Let's solve it carefully:\n\nIt's easier to calculate the complement: probability that ALL 30 people have DIFFERENT birthdays.\n\n1) Person 1: any birthday (365/365 = 1)\n2) Person 2: must be different from person 1 (364/365)\n3) Person 3: must be different from first two (363/365)\n...\n30) Person 30: must be different from first 29 (365-29)/365 = 336/365\n\nP(all different) = (365/365) ├ù (364/365) ├ù (363/365) ├ù ... ├ù (336/365)\nP(all different) = 365! / (335! ├ù 365^30)\n\nUsing approximation: P(all different) Γëê e^(-n(n-1)/(2├ù365))\n= e^(-30├ù29/730)\n= e^(-870/730)\n= e^(-1.192)\nΓëê 0.304\n\nSo P(at least one shared birthday) = 1 - 0.304 Γëê 0.696, or about 70%.\n\nThat's why it's called a paradox ΓÇö intuitively we'd expect it to be much lower, but with just 23 people the probability exceeds 50%.",        "response": "There's approximately a 70% chance that at least two of 30 people share a birthday. This is the birthday paradox: with 23 people the probability exceeds 50%, and at 70 people it's over 99.9%. The counterintuitive result comes from counting all possible pairs rather than individuals."    },    {        "question": "Write an efficient algorithm to find the kth largest element in an unsorted array.",        "reasoning": "Let me design this algorithm carefully:\n\nApproach 1 (naive): Sort the array, pick the kth from end ΓÇö O(n log n) time, O(1) space.\n\nApproach 2 (heap): Maintain a min-heap of size k, iterate through elements:\n- If heap size < k, push element\n- Else if element > heap[0], pop and push\nAt the end, heap[0] is the kth largest.\nTime: O(n log k), Space: O(k)\n\nApproach 3 (QuickSelect): Best approach for optimal performance.\n1) Choose a pivot (random pivot for expected O(n))\n2) Partition: elements > pivot go left, elements < pivot go right\n3) If pivot's position == k-1, return pivot\n4) If pivot's position < k-1, recurse on right subarray with adjusted k\n5) Else recurse on left subarray\n\nQuickSelect has O(n) average time, O(n┬▓) worst case (mitigated by random pivot).\n\nI'll implement QuickSelect as it's the most efficient:\n\n```python\nimport random\n\ndef find_kth_largest(nums, k):\n    def quickselect(left, right, k_smallest):\n        if left == right:\n            return nums[left]\n        pivot_idx = random.randint(left, right)\n        pivot_idx = partition(left, right, pivot_idx)\n        if k_smallest == pivot_idx:\n            return nums[pivot_idx]\n        elif k_smallest < pivot_idx:\n            return quickselect(left, pivot_idx - 1, k_smallest)\n        else:\n            return quickselect(pivot_idx + 1, right, k_smallest)\n    \n    def partition(left, right, pivot_idx):\n        pivot_val = nums[pivot_idx]\n        nums[pivot_idx], nums[right] = nums[right], nums[pivot_idx]\n        store_idx = left\n        for i in range(left, right):\n            if nums[i] > pivot_val:\n                nums[i], nums[store_idx] = nums[store_idx], nums[i]\n                store_idx += 1\n        nums[right], nums[store_idx] = nums[store_idx], nums[right]\n        return store_idx\n    \n    return quickselect(0, len(nums) - 1, k - 1)\n```\n\nTime: O(n) average, O(n┬▓) worst case. Space: O(log n) for recursion stack.",        "response": "Use QuickSelect, a variation of QuickSort. Average O(n) time: pick a pivot, partition around it (larger elements left, smaller right), and recurse on the appropriate side. For kth largest, partition with > on left side. Python implementation shown above."    },    {        "question": "Explain the concept of a derivative and why it matters.",        "reasoning": "Let me build this explanation from the ground up:\n\n1) Intuition: A derivative measures how much a function changes when its input changes. In physics, that's velocity (derivative of position with respect to time).\n\n2) Formal definition: f'(x) = lim[hΓåÆ0] (f(x+h) - f(x)) / h\nThis is the slope of the tangent line at point x.\n\n3) Geometric interpretation: If you zoom in infinitely close to a smooth function at point x, it looks like a straight line. The derivative is the slope of that line.\n\n4) Key rules:\n- Power rule: d/dx(x^n) = nx^(n-1)\n- Product rule: (fg)' = f'g + fg'\n- Chain rule: (f(g(x)))' = f'(g(x)) ├ù g'(x)\n\n5) Why it matters:\n- Optimization: Finding maxima/minima (set derivative = 0)\n- Machine learning: Gradient descent trains neural networks\n- Physics: Position ΓåÆ velocity ΓåÆ acceleration (derivatives up the chain)\n- Economics: Marginal cost/revenue = derivative of total cost/revenue\n- Engineering: Rates of change in control systems, fluid dynamics\n\n6) The derivative is the foundation of calculus and nearly all of modern science and engineering. Without derivatives, we couldn't optimize, couldn't train neural networks, couldn't model dynamic systems, and couldn't understand most physical phenomena quantitatively.",        "response": "The derivative measures instantaneous rate of change. Formally: f'(x) = lim[hΓåÆ0] (f(x+h)-f(x))/h. Geometrically it's the slope of the tangent line. It matters because: (1) Optimization uses derivatives to find minima/maxima, (2) Machine learning relies on gradient descent which uses derivatives, (3) Physics uses derivatives for velocity, acceleration, and field equations, (4) Economics uses them for marginal analysis."    },]# ΓöÇΓöÇΓöÇ Programming Example Templates ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇPROGRAMMING_EXAMPLES = [    {        "language": "Python",        "task": "Implement a singleton pattern",        "code": "class Singleton:\n    _instance = None\n    \n    def __new__(cls, *args, **kwargs):\n        if cls._instance is None:\n            cls._instance = super().__new__(cls)\n        return cls._instance\n    \n# Usage\ns1 = Singleton()\ns2 = Singleton()\nassert s1 is s2  # True\n\n# Thread-safe version:\nimport threading\nclass ThreadSafeSingleton:\n    _instance = None\n    _lock = threading.Lock()\n    \n    def __new__(cls, *args, **kwargs):\n        if cls._instance is None:\n            with cls._lock:\n                if cls._instance is None:\n                    cls._instance = super().__new__(cls)\n        return cls._instance",        "explanation": "The Singleton pattern ensures a class has only one instance. The __new__ method controls instance creation. Double-checked locking (check ΓåÆ lock ΓåÆ check again) provides thread safety with minimal overhead. Python's module system naturally provides singletons through module-level variables."    },    {        "language": "Python",        "task": "Asynchronous web scraper using aiohttp",        "code": "import asyncio\nimport aiohttp\nfrom bs4 import BeautifulSoup\n\nasync def fetch(session, url):\n    try:\n        async with session.get(url, timeout=aiohttp.ClientTimeout(total=10)) as response:\n            return await response.text(), url\n    except Exception as e:\n        return None, url\n\nasync def scrape(urls, concurrency=10):\n    connector = aiohttp.TCPConnector(limit=concurrency)\n    async with aiohttp.ClientSession(connector=connector) as session:\n        tasks = [fetch(session, url) for url in urls]\n        results = await asyncio.gather(*tasks)\n        \n        parsed = []\n        for html, url in results:\n            if html:\n                soup = BeautifulSoup(html, 'html.parser')\n                parsed.append({\n                    'url': url,\n                    'title': soup.title.string if soup.title else None,\n                    'text': soup.get_text()[:1000],\n                })\n        return parsed\n\n# Usage\nurls = ['https://example.com', 'https://python.org']\nresults = asyncio.run(scrape(urls))\nprint(f'Scraped {len(results)} pages')",        "explanation": "Async scraping outperforms sequential requests by making concurrent HTTP requests. The TCPConnector limits concurrent connections to avoid overwhelming servers. asyncio.gather runs tasks concurrently. Error handling ensures one failed request doesn't crash the entire batch."    },    {        "language": "JavaScript",        "task": "Implement a debounce function",        "code": "/**\n * Creates a debounced function that delays invoking func\n * until after `delay` ms have elapsed since the last invocation.\n */\nfunction debounce(func, delay = 300) {\n  let timeoutId = null;\n  \n  const debounced = (...args) => {\n    clearTimeout(timeoutId);\n    timeoutId = setTimeout(() => {\n      func.apply(this, args);\n      timeoutId = null;\n    }, delay);\n  };\n  \n  debounced.cancel = () => {\n    clearTimeout(timeoutId);\n    timeoutId = null;\n  };\n  \n  debounced.flush = () => {\n    if (timeoutId !== null) {\n      clearTimeout(timeoutId);\n      func.apply(this, args_cache);\n      timeoutId = null;\n    }\n  };\n  \n  let args_cache = [];\n  const originalDebounced = debounced;\n  \n  return debounced;\n}\n\n// Usage: debounced search input\nconst searchInput = document.getElementById('search');\nconst handleSearch = debounce((e) => {\n  console.log('Searching:', e.target.value);\n  // API call here\n}, 500);\nsearchInput.addEventListener('input', handleSearch);",        "explanation": "Debouncing limits how often a function executes by waiting for a pause in calls. Essential for search inputs (avoids API calls on every keystroke), window resize handlers, and button clicks. The cancel method allows cleanup, and flush forces immediate execution."    },    {        "language": "Rust",        "task": "Error handling with Result and Option",        "code": "use std::fs::File;\nuse std::io::{self, Read};\n\n#[derive(Debug)]\nenum AppError {\n    IoError(io::Error),\n    ParseError(String),\n    NotFound(String),\n}\n\nimpl From<io::Error> for AppError {\n    fn from(err: io::Error) -> AppError {\n        AppError::IoError(err)\n    }\n}\n\nfn read_config(path: &str) -> Result<String, AppError> {\n    let mut file = File::open(path)?;  // ? propagates io::Error\n    let mut contents = String::new();\n    file.read_to_string(&mut contents)?;\n    \n    if contents.is_empty() {\n        return Err(AppError::NotFound(path.to_string()));\n    }\n    \n    Ok(contents)\n}\n\nfn parse_port(config: &str) -> Result<u16, AppError> {\n    config\n        .lines()\n        .find(|line| line.starts_with(\"port=\"))\n        .and_then(|line| line.split('=').nth(1))\n        .and_then(|port| port.trim().parse::<u16>().ok())\n        .ok_or_else(|| AppError::ParseError(\"Port not found\".to_string()))\n}\n\nfn main() -> Result<(), AppError> {\n    let config = read_config(\"config.txt\")?;\n    let port = parse_port(&config)?;\n    println!(\"Server starting on port {}\", port);\n    Ok(())\n}",        "explanation": "Rust's ? operator propagates errors concisely. The From trait enables automatic error conversion. Custom error types with Into<IoError> make ? work across different error types. Option combinators (and_then, ok_or_else) chain optional operations with error handling."    },    {        "language": "Go",        "task": "Concurrent HTTP server with rate limiting",        "code": "package main\n\nimport (\n\t\"fmt\"\n\t\"net/http\"\n\t\"sync\"\n\t\"time\"\n)\n\ntype RateLimiter struct {\n\tmu       sync.Mutex\n\tvisitors map[string]*visitor\n\trate     int\n\tburst    int\n}\n\ntype visitor struct {\n\tlimiter  chan struct{}\n\tlastSeen time.Time\n}\n\nfunc NewRateLimiter(rate, burst int) *RateLimiter {\n\trl := &RateLimiter{\n\t\tvisitors: make(map[string]*visitor),\n\t\trate:     rate,\n\t\tburst:    burst,\n\t}\n\tgo rl.cleanup()\n\treturn rl\n}\n\nfunc (rl *RateLimiter) getVisitor(ip string) *visitor {\n\trl.mu.Lock()\n\tdefer rl.mu.Unlock()\n\t\n\tv, exists := rl.visitors[ip]\n\tif !exists {\n\t\tv = &visitor{\n\t\t\tlimiter:  make(chan struct{}, rl.burst),\n\t\t\tlastSeen: time.Now(),\n\t\t}\n\t\t// Fill token bucket\n\t\tgo rl.refill(v)\n\t\trl.visitors[ip] = v\n\t}\n\tv.lastSeen = time.Now()\n\treturn v\n}\n\nfunc (rl *RateLimiter) refill(v *visitor) {\n\tticker := time.NewTicker(time.Second / time.Duration(rl.rate))\n\tfor range ticker.C {\n\t\tselect {\n\t\tcase v.limiter <- struct{}{}:\n\t\tdefault:\n\t\t}\n\t}\n}\n\nfunc (rl *RateLimiter) cleanup() {\n\tfor {\n\t\ttime.Sleep(time.Minute)\n\t\trl.mu.Lock()\n\t\tfor ip, v := range rl.visitors {\n\t\t\tif time.Since(v.lastSeen) > 5*time.Minute {\n\t\t\t\tdelete(rl.visitors, ip)\n\t\t\t}\n\t\t}\n\t\trl.mu.Unlock()\n\t}\n}\n\nfunc rateLimitMiddleware(rl *RateLimiter, next http.HandlerFunc) http.HandlerFunc {\n\treturn func(w http.ResponseWriter, r *http.Request) {\n\t\tip := r.RemoteAddr\n\t\tv := rl.getVisitor(ip)\n\t\t\n\t\tselect {\n\t\tcase <-v.limiter:\n\t\t\tnext(w, r)\n\t\tdefault:\n\t\t\thttp.Error(w, \"Rate limit exceeded\", http.StatusTooManyRequests)\n\t\t}\n\t}\n}\n\nfunc handler(w http.ResponseWriter, r *http.Request) {\n\tfmt.Fprintf(w, \"Hello, you are rate limited!\")\n}\n\nfunc main() {\n\trl := NewRateLimiter(10, 20) // 10 req/s with burst of 20\n\thttp.HandleFunc(\"/api\", rateLimitMiddleware(rl, handler))\n\thttp.ListenAndServe(\":8080\", nil)\n}",        "explanation": "This implements a token bucket rate limiter. Each visitor gets a channel-based token bucket with configurable rate and burst. A background goroutine refills tokens, and another cleans up stale visitors. The sync.Mutex ensures thread-safe access to the visitors map."    },    {        "language": "Python",        "task": "Implement a decorator for memoization",        "code": "from functools import lru_cache, wraps\n\ndef memoize(func):\n    \"\"\"Custom memoization decorator with cache stats.\"\"\"\n    cache = {}\n    hits = 0\n    misses = 0\n    \n    @wraps(func)\n    def wrapper(*args, **kwargs):\n        nonlocal hits, misses\n        key = str(args) + str(sorted(kwargs.items()))\n        if key in cache:\n            hits += 1\n            return cache[key]\n        misses += 1\n        result = func(*args, **kwargs)\n        cache[key] = result\n        return result\n    \n    wrapper.cache_info = lambda: {'hits': hits, 'misses': misses, 'size': len(cache)}\n    wrapper.cache_clear = cache.clear\n    \n    return wrapper\n\n@memoize\ndef fibonacci(n):\n    if n < 2:\n        return n\n    return fibonacci(n-1) + fibonacci(n-2)\n\n# Python 3.9+ has built-in: @functools.cache\n# For bounded caches: @functools.lru_cache(maxsize=128)\n\nprint(fibonacci(100))  # 354224848179261915075 (instant!)\nprint(fibonacci.cache_info())  # {'hits': 98, 'misses': 101, 'size': 101}",        "explanation": "Memoization caches function results to avoid redundant computation. The wrapper transparently intercepts calls and checks the cache first. Using @wraps preserves the original function's metadata. Python's built-in @functools.lru_cache offers bounded caching with LRU eviction."    },]# ΓöÇΓöÇΓöÇ Multi-Turn Conversation Templates ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇMULTI_TURN_CONVERSATIONS = [    {        "domain": "programming",        "turns": [            ("user", "What's the difference between HTTP and HTTPS?"),            ("assistant", "HTTP (Hypertext Transfer Protocol) transfers data between web browsers and servers in plaintext. HTTPS (HTTP Secure) adds a layer of TLS/SSL encryption. With HTTPS, all data is encrypted including URLs, headers, and content. HTTPS also verifies server identity through digital certificates issued by Certificate Authorities. Always use HTTPS for any site handling sensitive data."),            ("user", "How does TLS encryption actually work?"),            ("assistant", "TLS uses a handshake process: 1) Client sends supported cipher suites and a random number. 2) Server responds with its certificate (containing public key), chosen cipher suite, and another random number. 3) Client verifies the certificate with the CA. 4) Client generates a pre-master secret, encrypts it with the server's public key. 5) Both sides derive session keys from the pre-master secret and random numbers. 6) They exchange 'Finished' messages encrypted with session keys. After handshake, all data uses symmetric encryption (AES-256 typically) for speed, while the handshake used asymmetric encryption (RSA/ECDHE) for secure key exchange."),            ("user", "What's the difference between TLS 1.2 and TLS 1.3?"),            ("assistant", "TLS 1.3 (finalized 2018) significantly improves on TLS 1.2: 1) Faster handshake ΓÇö 1 round trip instead of 2 (0-RTT for returning clients). 2) Removed insecure features ΓÇö no more RC4, 3DES, CBC mode ciphers, or static RSA key exchange. 3) Only forward-secret key exchanges (ECDHE) ΓÇö if the server's private key is compromised later, past sessions remain secure. 4) Simplified cipher suite list (only 5 AEAD ciphers vs dozens in TLS 1.2). 5) Encrypted handshake messages for better privacy. As of 2024, TLS 1.3 adoption is over 60% and growing."),        ]    },    {        "domain": "ai_ml",        "turns": [            ("user", "Can you explain how large language models work?"),            ("assistant", "Large Language Models (LLMs) like GPT-4, Claude, and Llama are deep neural networks trained on massive text datasets. They use the Transformer architecture with self-attention mechanisms that allow each token to 'attend' to all other tokens in the sequence. During training, they predict the next token given the previous ones ΓÇö this simple objective, scaled to billions of parameters and trillions of tokens, produces models with remarkable language understanding and generation capabilities."),            ("user", "What makes them 'understand' language rather than just pattern-match?"),            ("assistant", "This is a deep philosophical question! LLMs don't have understanding in the human sense ΓÇö they don't have consciousness, beliefs, or intentionality. They learn statistical patterns at an enormous scale. However, the debate about whether this constitutes 'understanding' is active. Some philosophers (Dennett, Searle) argue they're just symbol manipulators. Others argue that if a system can reason, explain, and generalize across domains ΓÇö as modern LLMs demonstrably can ΓÇö then calling it 'mere pattern matching' undersells what's happening. My view: LLMs learn structural patterns in language that correspond to real-world relationships, enabling genuine reasoning capabilities even without subjective experience. They understand language in a functional sense ΓÇö they can use it correctly, consistently, and creatively ΓÇö even if they don't have phenomenal consciousness."),            ("user", "What are the main limitations of current LLMs?"),            ("assistant", "Key limitations include: 1) Hallucination ΓÇö generating confident but false information, because they have no ground truth mechanism. 2) No persistent memory ΓÇö context windows, while growing (1M+ tokens for Gemini, 200K for GPT-4), are still limited. 3) No true reasoning ΓÇö they can simulate reasoning but can be fooled by simple logic puzzles and make arithmetic errors. 4) Training cutoff ΓÇö knowledge is frozen at training time. 5) No causal understanding ΓÇö they correlate but don't understand causation. 6) Brittleness ΓÇö small changes in prompting can cause dramatic output differences. 7) Bias ΓÇö they reflect biases in training data. 8) Cost ΓÇö inference is expensive. Ongoing research addresses all of these through RAG, fine-tuning, chain-of-thought, constitutional AI, and more efficient architectures."),        ]    },    {        "domain": "cybersecurity",        "turns": [            ("user", "What's the most important cybersecurity practice for a small business?"),            ("assistant", "For small businesses, the single most impactful practice is enabling Multi-Factor Authentication (MFA) on every account that supports it ΓÇö email, banking, cloud services, admin panels. MFA prevents 99.9% of automated attacks according to Microsoft. Second: regular automated backups (3-2-1 rule: 3 copies, 2 different media, 1 off-site). Third: keep software updated. Fourth: employee security training ΓÇö phishing is the most common entry vector. Fifth: use a password manager and enforce strong, unique passwords."),            ("user", "How do I set up MFA properly?"),            ("assistant", "Proper MFA setup: 1) Use authenticator apps (Google Authenticator, Authy, Microsoft Authenticator) rather than SMS when possible ΓÇö SIM swapping can bypass SMS-based MFA. 2) For each service: enable MFA in security settings, scan the QR code with your authenticator app, save the backup codes somewhere safe (encrypted, offline). 3) Use hardware security keys (YubiKey, Nitrokey) for admin accounts and critical services ΓÇö they're phishing-resistant. 4) Setup recovery: print backup codes and store in a safe place, consider a break-glass account with emergency access. 5) Regular audit: quarterly review who has access and remove unused accounts."),            ("user", "What should I do if I suspect a breach?"),            ("assistant", "Incident response steps: 1) DISCONNECT ΓÇö isolate affected systems from the network immediately to prevent lateral movement. DON'T turn them off (you may lose forensic evidence). 2) ASSESS ΓÇö determine what was accessed, when, and how. Check logs, alert systems, and file integrity. 3) NOTIFY ΓÇö inform relevant parties (IT team, management, legal counsel). For data breaches, you may need to notify affected users and regulators (within 72 hours under GDPR). 4) CONTAIN ΓÇö rotate all credentials (passwords, API keys, certificates), revoke sessions, patch the vulnerability. 5) ERADICATE ΓÇö remove malware, rebuild affected systems from clean backups. 6) RECOVER ΓÇö restore from verified backups, test systems before returning to production. 7) POST-MORTEM ΓÇö analyze root cause, document lessons learned, update security policies. Consider engaging a professional incident response team and forensic experts."),        ]    },]# ΓöÇΓöÇΓöÇ Data Generation Logic ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_single_turn(domain: str, config: dict, difficulty: str) -> dict:    """Generate a single-turn Q&A pair for a domain."""    question = random.choice(generate_domain_questions(domain, config["family"], difficulty))    answer = generate_knowledge_response(domain, config["family"], difficulty, question)    system_prompt = random.choice(config["system_prompts"])    return {        "messages": [            {"role": "system", "content": system_prompt},            {"role": "user", "content": question},            {"role": "assistant", "content": answer},        ],        "metadata": {            "domain": domain,            "family": config["family"],            "difficulty": difficulty,            "type": "single_turn",        }    }def generate_cot_example(idx: int) -> dict:    """Generate a chain-of-thought reasoning example."""    example = COT_EXAMPLES[idx % len(COT_EXAMPLES)]    return {        "messages": [            {"role": "system", "content": "You are NICTO, an AI assistant that solves problems step-by-step. Show your reasoning clearly before giving the final answer."},            {"role": "user", "content": example["question"]},            {"role": "assistant", "content": f"Let me think through this carefully.\n\n{example['reasoning']}\n\nFinal answer: {example['response']}"},        ],        "metadata": {            "domain": "reasoning",            "family": "General",            "difficulty": "medium",            "type": "chain_of_thought",        }    }def generate_programming_example(idx: int) -> dict:    """Generate a programming example."""    example = PROGRAMMING_EXAMPLES[idx % len(PROGRAMMING_EXAMPLES)]    system_prompts = {        "Python": "You are NICTO, a Python expert. You write clean, idiomatic, well-documented Python code.",        "JavaScript": "You are NICTO, a JavaScript expert. You write modern, performant JavaScript with best practices.",        "Rust": "You are NICTO, a Rust expert. You write safe, idiomatic Rust code with proper error handling.",        "Go": "You are NICTO, a Go expert. You write clean, concurrent Go code following best practices.",    }    return {        "messages": [            {"role": "system", "content": system_prompts.get(example["language"], "You are NICTO, a programming expert.")},            {"role": "user", "content": f"Write {example['task']} in {example['language']}."},            {"role": "assistant", "content": f"```{example['language'].lower()}\n{example['code']}\n```\n\n{example['explanation']}"},        ],        "metadata": {            "domain": "programming",            "family": "Formal Sciences",            "difficulty": "medium",            "type": "code",            "language": example["language"],        }    }def generate_multi_turn(idx: int) -> dict:    """Generate a multi-turn conversation."""    conv = MULTI_TURN_CONVERSATIONS[idx % len(MULTI_TURN_CONVERSATIONS)]    # Build system prompt based on domain    domain_config = DOMAIN_CONFIGS.get(conv["domain"])    if domain_config:        system_prompt = random.choice(domain_config["system_prompts"])    else:        system_prompt = random.choice(SPECIAL_SYSTEM_PROMPTS)    messages = [{"role": "system", "content": system_prompt}]    for role, content in conv["turns"]:        messages.append({"role": role, "content": content})    return {        "messages": messages,        "metadata": {            "domain": conv["domain"],            "family": DOMAIN_CONFIGS.get(conv["domain"], {}).get("family", "General"),            "difficulty": "medium",            "type": "multi_turn",        }    }def generate_cross_domain(domains: List[str], configs: dict) -> dict:    """Generate a cross-domain synthesis example."""    d1, d2 = random.sample(domains, 2)    c1, c2 = configs[d1], configs[d2]    question = f"How would you connect concepts from {d1.title()} and {d2.title()}? What insights emerge at their intersection?"    system_prompt = f"You are NICTO, an AI that synthesizes knowledge across disciplines. You connect ideas from {d1.title()} and {d2.title()} to generate novel insights."    answer = (        f"Connecting {d1.title()} and {d2.title()} reveals fascinating cross-disciplinary insights.\n\n"        f"From {d1.title()} ({c1['family']}), we bring concepts such as foundational theories and analytical frameworks "        f"that help us understand structured systems and processes.\n\n"        f"From {d2.title()} ({c2['family']}), we bring approaches to understanding complex systems and human phenomena, "        f"including observational and interpretive methodologies.\n\n"        f"At their intersection: {cross_domain_synthesis(d1, d2)}\n\n"        f"This cross-pollination of ideas demonstrates how knowledge boundaries are artificial ΓÇö "        f"the most powerful insights often come from combining perspectives from different fields."    )    return {        "messages": [            {"role": "system", "content": system_prompt},            {"role": "user", "content": question},            {"role": "assistant", "content": answer},        ],        "metadata": {            "domain": f"{d1}+{d2}",            "family": "Cross-Domain",            "difficulty": "hard",            "type": "cross_domain",        }    }def cross_domain_synthesis(d1: str, d2: str) -> str:    """Generate a meaningful cross-domain synthesis statement."""    synthesis_templates = [        f"computational models from {d1.title()} can help analyze complex patterns in {d2.title()}, revealing hidden structures that traditional {d2.title()} methods might miss",        f"the rigorous analytical frameworks of {d1.title()} provide new tools for understanding the emergent phenomena studied in {d2.title()}",        f"applying the systems thinking of {d1.title()} to {d2.title()} challenges enables more holistic solutions that account for multiple interacting factors",        f"the data-driven approaches from {d1.title()} complement the qualitative insights of {d2.title()}, enabling mixed-method research that is both precise and contextually rich",        f"theoretical advances in {d1.title()} are enabling new experimental paradigms in {d2.title()}, particularly in modeling complex systems and predicting emergent behaviors",    ]    return random.choice(synthesis_templates)# ΓöÇΓöÇΓöÇ Main Generation Pipeline ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_dataset(    single_turn_per_domain: int = 800,    multi_turn_count: int = 500,    cot_count: int = 1000,    programming_count: int = 1000,    cross_domain_count: int = 500,    output_path: Optional[Path] = None,) -> Tuple[List[dict], dict]:    """Generate the complete training dataset."""    print("=" * 60)    print("  NICTO SUPER TRAINING DATA ENGINE")    print("=" * 60)    start_time = time.time()    output_path = output_path or OUTPUT_FILE    output_path.parent.mkdir(parents=True, exist_ok=True)    all_examples = []    domains = list(DOMAIN_CONFIGS.keys())    stats = {"domains": {}, "total": 0}    # Phase 1: Single-turn Q&A per domain    print(f"\nPhase 1: Single-turn Q&A ({len(domains)} domains, ~{single_turn_per_domain}/domain)...")    phase1_start = time.time()    for domain in domains:        config = DOMAIN_CONFIGS[domain]        difficulty_samples = {}        for difficulty, weight in config["difficulty_weights"].items():            count = int(single_turn_per_domain * weight)            difficulty_samples[difficulty] = count        domain_examples = []        for difficulty, count in difficulty_samples.items():            for i in range(count):                example = generate_single_turn(domain, config, difficulty)                domain_examples.append(example)        all_examples.extend(domain_examples)        stats["domains"][domain] = {            "single_turn": len(domain_examples),            "difficulty_breakdown": dict(difficulty_samples),        }    elapsed = time.time() - phase1_start    print(f"  Generated {sum(s['single_turn'] for s in stats['domains'].values())} examples in {elapsed:.1f}s")    # Phase 2: Multi-turn conversations    print(f"\nPhase 2: Multi-turn conversations ({multi_turn_count})...")    phase2_start = time.time()    for i in range(multi_turn_count):        example = generate_multi_turn(i)        all_examples.append(example)        domain = example["metadata"]["domain"]        if domain not in stats["domains"]:            stats["domains"][domain] = {}        stats["domains"][domain]["multi_turn"] = stats["domains"][domain].get("multi_turn", 0) + 1    print(f"  Generated {multi_turn_count} in {time.time() - phase2_start:.1f}s")    # Phase 3: Chain-of-thought reasoning    print(f"\nPhase 3: Chain-of-thought reasoning ({cot_count})...")    phase3_start = time.time()    for i in range(cot_count):        example = generate_cot_example(i)        all_examples.append(example)    print(f"  Generated {cot_count} in {time.time() - phase3_start:.1f}s")    # Phase 4: Programming examples    print(f"\nPhase 4: Programming examples ({programming_count})...")    phase4_start = time.time()    for i in range(programming_count):        example = generate_programming_example(i)        all_examples.append(example)    print(f"  Generated {programming_count} in {time.time() - phase4_start:.1f}s")    # Phase 5: Cross-domain synthesis    print(f"\nPhase 5: Cross-domain synthesis ({cross_domain_count})...")    phase5_start = time.time()    for i in range(cross_domain_count):        example = generate_cross_domain(domains, DOMAIN_CONFIGS)        all_examples.append(example)    print(f"  Generated {cross_domain_count} in {time.time() - phase5_start:.1f}s")    # Shuffle    random.shuffle(all_examples)    # Save    print(f"\nSaving {len(all_examples)} examples...")    with open(output_path, "w", encoding="utf-8") as f:        for example in all_examples:            # Strip metadata before saving (ChatML format)            save_obj = {"messages": example["messages"]}            f.write(json.dumps(save_obj) + "\n")    # Compute stats    total = len(all_examples)    type_counts = {}    difficulty_counts = {}    for ex in all_examples:        meta = ex["metadata"]        t = meta["type"]        d = meta["difficulty"]        type_counts[t] = type_counts.get(t, 0) + 1        difficulty_counts[d] = difficulty_counts.get(d, 0) + 1    metadata = {        "total_examples": total,        "domains_covered": len(domains),        "type_breakdown": type_counts,        "difficulty_breakdown": difficulty_counts,        "generation_time_seconds": time.time() - start_time,        "generated_at": time.time(),    }    stats["metadata"] = metadata    # Save metadata    metadata_path = output_path.with_name("super_nicto_metadata.json")    with open(metadata_path, "w") as f:        json.dump(metadata, f, indent=2)    print()    print("=" * 60)    print(f"  GENERATION COMPLETE")    print(f"  Total examples: {total}")    print(f"  Domains: {len(domains)}")    print(f"  Type breakdown: {json.dumps(type_counts, indent=4)}")    print(f"  Difficulty: {json.dumps(difficulty_counts, indent=4)}")    print(f"  Time: {time.time() - start_time:.1f}s")    print(f"  Output: {output_path}")    print(f"  Metadata: {metadata_path}")    print("=" * 60)    return all_examples, metadatadef main():    """Run the data generator with configurable counts."""    import argparse    parser = argparse.ArgumentParser(description="NICTO Super Training Data Generator")    parser.add_argument("--single-turn", type=int, default=800, help="Single-turn examples per domain (default: 800)")    parser.add_argument("--multi-turn", type=int, default=500, help="Multi-turn conversations (default: 500)")    parser.add_argument("--cot", type=int, default=1000, help="Chain-of-thought examples (default: 1000)")    parser.add_argument("--programming", type=int, default=1000, help="Programming examples (default: 1000)")    parser.add_argument("--cross-domain", type=int, default=500, help="Cross-domain examples (default: 500)")    parser.add_argument("--output", type=str, default=None, help="Output file path")    args = parser.parse_args()    output_path = Path(args.output) if args.output else None    generate_dataset(        single_turn_per_domain=args.single_turn,        multi_turn_count=args.multi_turn,        cot_count=args.cot,        programming_count=args.programming,        cross_domain_count=args.cross_domain,        output_path=output_path,    )if __name__ == "__main__":    main()